#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100000
#define INF 0x3f3f3f3f

int min(int a, int b) { return a < b ? a : b; }
int max(int a, int b) { return a > b ? a : b; }

int main() {
    int N, Q, R, key, u, v, k, t, last_answer = 0;
    scanf("%d %d", &N, &Q);
    scanf("%d %d", &R, &key);
    int graph[N][N] = {0};
    int keys[N] = {0};
    keys[R - 1] = key;
    for (int i = 0; i < N - 1; i++) {
        scanf("%d %d %d", &u, &v, &k);
        graph[u - 1][v - 1] = 1;
        keys[v - 1] = k;
    }
    for (int i = 0; i < Q; i++) {
        scanf("%d", &t);
        t ^= last_answer;
        if (t == 0) {
            scanf("%d %d %d", &v, &u, &k);
            v ^= last_answer;
            u ^= last_answer;
            k ^= last_answer;
            graph[v - 1][u - 1] = 1;
            keys[u - 1] = k;
        } else {
            scanf("%d %d", &v, &k);
            v ^= last_answer;
            k ^= last_answer;
            int min_val = INF, max_val = -INF;
            for (int j = 0; j < N; j++) {
                if (graph[v - 1][j] == 1) {
                    min_val = min(min_val, keys[j] ^ k);
                    max_val = max(max_val, keys[j] ^ k);
                }
            }
            printf("%d %d\n", min_val, max_val);
            last_answer = min_val ^ max_val;
        }
    }
    return 0;
}

